/* Types */
export type AdoptWorktreeRequest = {
	path: string,
	title: string,
};

export type AgentKind = "claude" | "copilot";

export type AgentStatus = {
	thread_id: ThreadId,
	pane_target: string,
	state: AgentStatusState,
	detail: string | null,
	updated_at: Timestamp,
};

export type AgentStatusState = "idle" | "running" | "awaiting_user" | "stopped" | "error";

/**
 *  One open or closed agent turn. Open rows render as live in-progress
 *  entries in the Work panel; the Stop hook closes the row.
 */
export type AgentTurn = {
	id: AgentTurnId,
	thread_id: ThreadId,
	work_item_id: WorkItemId | null,
	prompt: string,
	answer: string | null,
	session_id: string | null,
	started_at: Timestamp,
	ended_at: Timestamp | null,
};

export type AgentTurnId = string;

export type AheadBehind = {
	ahead: number,
	behind: number,
};

/**
 *  One file's content at one side of the diff. `content == None` means
 *  the file did not exist on that side (e.g. add/delete).
 */
export type AnalyzeFileSpec = {
	path: string,
	base_content: string | null,
	head_content: string | null,
};

export type AnalyzeFunctionsResult = {
	sides: AnalyzedFileSide[],
};

export type AnalyzedFileSide = {
	path: string,
	// `"base"` or `"head"`.
	side: string,
	functions: AnalyzedFunction[],
};

// Function metadata for one (path, side) pair.
export type AnalyzedFunction = {
	name: string,
	start_line: number,
	length: number,
	complexity: number,
	parameter_count: number,
	nloc: number,
};

export type AppVersion = {
	version: string,
};

/**
 *  Result of `attach_or_create` — the session id plus a base64
 *  snapshot of the replay buffer that the renderer should write into
 *  a fresh xterm before starting to consume live events.
 */
