export type SnapshotPairDiff = {
	before: FileSnapshot | null,
	after: FileSnapshot | null,
	/**
	 *  True when the two captures hash differently (i.e. content
	 *  changed between them). Always false when either side is None.
	 */
	changed: boolean,
};

export type SnapshotSummary = {
	snapshot: FileSnapshot,
	previousSnapshotId: string | null,
	files: { [key in string]: SnapshotFileRow },
	counts: SnapshotSummaryCounts,
};

export type SnapshotSummaryCounts = {
	created: number,
	updated: number,
	deleted: number,
};

export type Stream = {
	id: StreamId,
	kind: StreamKind,
	title: string,
	branch: string,
	branch_ref: string,
	branch_source: string,
	worktree_path: string,
	working_pane: string,
	talking_pane: string,
	working_session_id: string,
	talking_session_id: string,
	/**
	 *  Standing instructions appended to every agent system prompt
	 *  when this stream is active. `None` (or empty) clears it.
	 */
	custom_prompt: string | null,
	created_at: Timestamp,
	updated_at: Timestamp,
	/**
	 *  Set when the stream was archived via the rail's "Remove…"
	 *  action. Archived streams are filtered out of `StreamStore::list`
	 *  so they disappear from the rail; the row stays in the DB so
	 *  history references (efforts, snapshots, page_visit) don't
	 *  dangle.
	 */
	archived_at: Timestamp | null,
};

export type StreamId = string;

// Whether a stream is the project's primary stream or a worktree.
export type StreamKind = "primary" | "worktree";

export type TextSearchHit = {
	path: string,
	line: number,
	snippet: string,
};

export type Thread = {
	id: ThreadId,
	stream_id: StreamId,
	title: string,
	status: ThreadStatus,
	sort_index: number,
	// Which pane (working/talking) is the agent's primary attach point.
	pane_target: string,
	resume_session_id: string,
	summary: string,
	summary_updated_at: Timestamp | null,
	/**
	 *  Timestamp when the thread was closed (status transitions to
	 *  `Closed`). `None` for active/queued threads.
	 */
	closed_at: Timestamp | null,
	/**
	 *  Per-thread custom prompt appended to the agent's system message.
	 *  `None` when unset; `Some("")` is distinct (empty override).
	 */
	custom_prompt: string | null,
	created_at: Timestamp,
	updated_at: Timestamp,
	/**
	 *  Set when the thread was archived as part of its stream's
	 *  "Remove…" action. Archived threads are filtered out of
	 *  `ThreadStore::list_for_stream`.
	 */
	archived_at: Timestamp | null,
};

export type ThreadId = string;

export type ThreadState = {
	selectedThreadId: ThreadId | null,
	activeThreadId: ThreadId | null,
	threads: Thread[],
};

/**
 *  Thread lifecycle status — mirrors the TS `ThreadState` shape.
 * 
 *  `Active` is the writer thread for its stream (only one per stream
 *  can mutate the worktree at a time). `Queued` is a non-writer
 *  thread sharing the same worktree in read-only mode. `Closed` is
 *  terminated; closed threads are excluded from the rail.
 */
export type ThreadStatus = "active" | "queued" | "closed";

export type ThreadWorkState = {
	threadId: ThreadId,
	waiting: WorkItem[],
	inProgress: WorkItem[],
	done: WorkItem[],
	epics: WorkItem[],
	items: WorkItem[],
	followups: Followup[],
};

// Wall-clock UTC timestamp serialized as RFC 3339 strings.
export type Timestamp = string;

export type UiLogEntry = {
	clientId: string | null,
	level: string,
	message: string,
	/**
	 *  JSON-encoded structured context (the renderer stringifies its
	 *  own object so the boundary is plain `Option<String>`).
	 */
	context: string | null,
	timestamp: string | null,
};

/**
 *  Partial-patch for `update_work_item`. Each `Option` follows
 *  "missing -> keep, present -> replace" semantics. `category` and
 *  `tags` use a wrapping `Option<Option<…>>`-via-helper pattern to
 *  distinguish "keep" from "clear"; in this struct, `null` clears and
 *  missing keeps.
 */
export type UpdateWorkItemChanges = {
	title: string | null,
	description: string | null,
	acceptance_criteria: string | null,
	parent_id: WorkItemId | null,
	status: WorkItemStatus | null,
	priority: WorkItemPriority | null,
	category: string | null,
	tags: string | null,
};

export type UpdateWorkItemRequest = {
	id: WorkItemId,
	changes: UpdateWorkItemChanges,
};

export type UsageEvent = {
	id: string,
	kind: string,
	payload_json: string,
	occurred_at: Timestamp,
};

/**
 *  Per-key aggregation of usage events. Returned by
 *  `SqliteUsageStore::list_recent_rollup` for callers that want
 *  "most-recently-touched X" lists rather than the raw event log
 *  (e.g. the WikiActivityBar's recent-files strip).
 */
export type UsageRollup = {
	kind: string,
	key: string,
	last_at: Timestamp,
	count: number,
};

export type VisitedPage = {
	page_kind: string,
	page_id: string,
	visit_count: number,
};

export type WikiPage = {
	slug: string,
	title: string,
	body_path: string,
	body_excerpt: string,
	body_size_bytes: number,
	file_refs: string[],
	dir_refs: string[],
	related_notes: string[],
	created_at: Timestamp,
	updated_at: Timestamp,
};

export type WikiPageSearchHit = {
	slug: string,
	title: string,
	snippet: string,
	updated_at: Timestamp,
};

/**
 *  A work item row.
 * 
 *  Field shape mirrors the TS interface so JSON payloads are
 *  indistinguishable across the migration. Nullable timestamps stay
 *  `Option<Timestamp>` rather than collapsing to a sentinel — a missing
 *  `completed_at` and a "completed at the epoch" must be distinguishable.
 */
export type WorkItem = {
	id: WorkItemId,
	// `None` when the item is on the project-wide backlog.
	thread_id: ThreadId | null,
	parent_id: WorkItemId | null,
	kind: WorkItemKind,
	title: string,
	description: string,
	acceptance_criteria: string | null,
	status: WorkItemStatus,
	priority: WorkItemPriority,
	sort_index: number,
	created_by: WorkItemActorKind,
	created_at: Timestamp,
	updated_at: Timestamp,
	completed_at: Timestamp | null,
	deleted_at: Timestamp | null,
	note_count: number,
	// Legacy rows have `None`; v29+ rows are always populated.
	author: WorkItemAuthor | null,
	// Free-text grooming bucket used by the Backlog page's group-by.
	category: string | null,
	// Comma-separated tags used by the Backlog page filter chips.
	tags: string | null,
};

// Who or what wrote a work-item row to the DB.
export type WorkItemActorKind = "user" | "agent" | "system";

/**
 *  Semantic origin — distinct from `created_by` (the writer).
 * 
 *  Narrowed to user/agent after auto-file was removed in v29+. Legacy
 *  `agent-auto` rows get mapped to `None` on read.
 */
export type WorkItemAuthor = "user" | "agent";

export type WorkItemEffort = {
	id: EffortId,
	work_item_id: WorkItemId,
	thread_id: ThreadId,
	started_at: Timestamp,
	ended_at: Timestamp | null,
	start_snapshot_id: number | null,
	end_snapshot_id: number | null,
	summary: string | null,
};

// Audit-log entry for state changes on a work item.
export type WorkItemEvent = {
	id: string,
	thread_id: ThreadId,
	item_id: WorkItemId | null,
	event_type: string,
	actor_kind: WorkItemActorKind,
	actor_id: string,
	payload_json: string,
	created_at: Timestamp,
};

export type WorkItemId = string;

/**
 *  What kind of work item this is.
 * 
 *  The hierarchy: `epic` parents `task`s parent `subtask`s. `bug` and
 *  `note` are flat — they don't normally parent anything.
 */
export type WorkItemKind = "epic" | "task" | "subtask" | "bug" | "note";

export type WorkItemPriority = "low" | "medium" | "high" | "urgent";

export type WorkItemStatus = "ready" | "in_progress" | "blocked" | "done" | "canceled" | "archived";

/**
 *  A note attached to either a work item or a thread (mutually
 *  exclusive — enforced at the DB CHECK constraint).
 */
export type WorkNote = {
	id: NoteId,
	work_item_id: WorkItemId | null,
	thread_id: ThreadId | null,
	body: string,
	author: string,
	created_at: Timestamp,
};

export type WorkspaceContext = {
	project_dir: string,
	default_branch: string | null,
	is_git_repo: boolean,
};

export type WorkspaceEntry = {
	name: string,
	path: string,
	kind: WorkspaceEntryKind,
	git_status: GitFileStatus | null,
	has_changes: boolean,
};

export type WorkspaceEntryKind = "file" | "directory";

export type WorkspaceFile = {
	path: string,
	content: string,
};

export type WorkspaceIndexedFile = {
	path: string,
	git_status: GitFileStatus | null,
};

export type WorkspaceStatusSummary = {
	modified: number,
	added: number,
	deleted: number,
	renamed: number,
	untracked: number,
	total: number,
};

/* Tauri Specta runtime */
async function typedError<T, E>(result: Promise<T>): Promise<{ status: "ok"; data: T } | { status: "error"; error: E }> {
    try {
        return { status: "ok", data: await result };
    } catch (e) {
        if (e instanceof Error) throw e;
        return { status: "error", error: e as any };
    }
}

